import { useEffect, useState } from 'react';
import Loader from 'react-loaders';
import { Link } from 'react-router-dom';
import AnimatedLetters from '../AnimatedLetters';
import './index.scss';
import LaLigaLogo from '../../assets/images/laliga-logo.png';

const Home = () => {
    const [letterClass, setLetterClass] = useState('text-animate')
    const nameArray = "Welcome to".split("");
    const jobArray = "LaLiga Zone Fantasy!".split("");

    useEffect(() => {
        const timerId = setTimeout(() => {
          setLetterClass('text-animate-hover');
        }, 4000);

        return () => {
          clearTimeout(timerId);
        };
      }, []);

    return(
      <>
        <div className = "container home-page">
            <div className="text-zone">
                <h1>
                <img src={LaLigaLogo} alt="LaLiga logo" />
                <br />
                <AnimatedLetters letterClass={letterClass} strArray={nameArray} idx={12} />
                <br /> 
                <AnimatedLetters letterClass={letterClass} strArray={jobArray} idx={15} /> 
                </h1>
                <h2>Your home for everything LaLiga related!</h2>
                <Link to="/teams" className="flat-button">GET STARTED</Link>
                <div className="feature-grid">
                  <Link className="feature-card" to="/teams">
                    <h3>Teams Hub</h3>
                    <p>Browse all LaLiga clubs and open each squad quickly.</p>
                  </Link>
                  <Link className="feature-card" to="/position">
                    <h3>Position Scout</h3>
                    <p>Filter players by goalkeeper, defender, midfield, and attack.</p>
                  </Link>
                  <Link className="feature-card" to="/nation">
                    <h3>Nation View</h3>
                    <p>Explore players by nationality and compare talent pools.</p>
                  </Link>
                  <Link className="feature-card" to="/predictions">
                    <h3>Match Predictions</h3>
                    <p>See upcoming fixtures with win probabilities and outcomes.</p>
                  </Link>
                </div>
            </div>
        </div>
        <Loader type="pacman" />
      </>
    )
}

export default Home
